attributes.visState:
{"aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "data": {
    "url": {
      "%context%": true,
      "%timefield%": "event.ingested",
      "index": "metrics-shard-esdiag",
      "body": {
        "size": 0,
        "aggs": {
          "phase": {
            "terms": {
             "field": "index.ilm.phase"
            },
            "aggs": {
              "store_size": {
                "boxplot": {
                  "field": "shard.store.total_data_set_size_in_bytes"
                }
              }
            }
          }
        }
      }
    },
    "format": {"property": "aggregations.phase.buckets"}
  },
  "transform": [
    {"calculate": "format(datum.store_size.lower/1073741824, '0.2f')", "as": "lower"},
    {"calculate": "format(datum.store_size.upper/1073741824, '0.2f')", "as": "upper"},
    {"calculate": "format(datum.store_size.q1/1073741824, '0.2f')", "as": "q1"},
    {"calculate": "format(datum.store_size.q2/1073741824, '0.2f')", "as": "q2"},
    {"calculate": "format(datum.store_size.q3/1073741824, '0.2f')", "as": "q3"},
    {"calculate": "format(datum.store_size.min/1073741824, '0.2f')", "as": "min"},
    {"calculate": "format(datum.store_size.max/1073741824, '0.2f')", "as": "max"},
    {"calculate": "datum.key", "as": "phase"},
    {"calculate": "0", "as": "min-y"},
    {"calculate": "10", "as": "low-y"},
    {"calculate": "20", "as": "mid-y1"},
    {"calculate": "40", "as": "mid-y2"},
    {"calculate": "50", "as": "mid-y3"},
    {"calculate": "80", "as": "high-y"},
    {"calculate": "100", "as": "max-y"}

  ],
  "encoding": {
    "x": {
      "field": "phase",
      "type": "nominal",
      "title": null,
      "sort": ["new","hot","warm","cold","frozen","delete"],
      "axis": {
        "labelAngle": 0
      }
    }
  },
  "layer": [
    {
      "mark": {"type": "rule", "tooltip":true, "size":2},
      "encoding": {
        "y": {
          "field": "lower", 
          "type": "quantitative",
          "scale": {"domain":[0,100], "clamp": true}, 
          "title": null
        },
        "y2": {"field": "upper"}
      },
      "title": null
    },
    {
      "mark": "rect",
      "encoding": {
        "y": {"field": "min-y", "type":"quantitative", "scale": {"domain": [0, 100]}},
        "y2": {"field": "low-y", "type": "quantitative", "scale": {"domain": [0, 100]}},
        "color": {"value": "#ee60861A"}
      }
    },
    {
      "mark": "rect",
      "encoding": {
        "y": {"field": "low-y", "type":"quantitative", "scale": {"domain": [0, 100]}},
        "y2": {"field": "mid-y1", "type": "quantitative", "scale": {"domain": [0, 100]}},
        "color": {"value": "#6092ee1A"}
      }
    },
   {
      "mark": "rect",
      "encoding": {
        "y": {"field": "mid-y1", "type":"quantitative", "scale": {"domain": [0, 100]}},
        "y2": {"field": "mid-y2", "type": "quantitative", "scale": {"domain": [0, 100]}},
        "color": {"value": "#54ee991A"}
      }
    },
    {
      "mark": "rect",
      "encoding": {
        "y": {"field": "mid-y2", "type":"quantitative", "scale": {"domain": [0, 100]}},
        "y2": {"field": "mid-y3", "type": "quantitative", "scale": {"domain": [0, 100]}},
        "color": {"value": "#6092ee1A"}
      }
    },
    {
      "mark": "rect",
      "encoding": {
        "y": {"field": "mid-y3", "type":"quantitative", "scale": {"domain": [0, 100]}},
        "y2": {"field": "high-y", "type": "quantitative", "scale": {"domain": [0, 100]}},
        "color": {"value": "#eeee571A"}
      }
    },
    {
      "mark": "rect",
      "encoding": {
        "y": {"field":"high-y", "type": "quantitative", "scale": {"domain": [0, 100]}},
        "y2": {"field":"max-y", "type": "quantitative", "scale": {"domain": [0, 100]}},
        "color": {"value": "#ee60861A"}
      }
    },
    {
      "mark": {"type": "bar",  "cornerRadius": 3, "tooltip": true},
      "encoding": {
        "y": {"field": "q1", "type": "quantitative", "title": "p25"},
        "y2": {"field": "q3", "title": "p75"},
        "color": {"field": "phase", "type": "nominal", "legend": null}
      }
    },
    {
      "mark": {"type": "tick", "color": "white", "thickness": 2, "tooltip":true},
      "encoding": {
        "y": {"field": "q2", "type": "quantitative", "title":"Mean"}
      }
    },
    {
      "mark": {"type": "point", "tooltip": true},
      "encoding": {
        "y": {"field": "min", "type": "quantitative"}
      }
    },
    {
      "mark": {"type": "point", "tooltip": true},
      "encoding": {
        "y": {"field": "max", "type": "quantitative"}
      }
    }
  ]
}"},"title":"Shard Size by ILM Phase","type":"vega"}
